// // This comment suggests that the clock gating circuit will only propagate the clock when TE is low and EN is high.
module top_module(
  input CLK,
  input EN,
  input TE,
  output reg ENCLK
);always @(*) begin
    if (TE) begin
      ENCLK <= 0;
    end else if (EN) begin
      ENCLK <= CLK;
    end else begin
      ENCLK <= 0;
    end
  end

endmodule
